class Solution {
public:
    vector<int> maxSumOfThreeSubarrays(vector<int>& a, int k) {
        int n=a.size(); vector<int> ps(n+1); for(int i=0;i<n;i++) ps[i+1]=ps[i]+a[i];
        auto sum=[&](int i){ return ps[i+k]-ps[i]; };
        vector<int> L(n), R(n); int best=0, idx=0;
        for(int i=0;i<=n-k;i++){ if(sum(i)>best){ best=sum(i); idx=i; } L[i]=idx; }
        best=0; idx=0;
        for(int i=n-k;i>=0;i--){ if(sum(i)>=best){ best=sum(i); idx=i; } R[i]=idx; }
        vector<int> ans={0,0,0}; int bs=-1;
        for(int j=k;j<=n-2*k;j++){
            int i=L[j-k], l=R[j+k], s=sum(i)+sum(j)+sum(l);
            if(s>bs){ bs=s; ans={i,j,l}; }
        }
        return ans;
    }
};
